import React from "react"
import { type GoogleAuthContextValue, useGoogleAuth } from "./context"

// ─── Types ─────────────────────────────────────────────────────────────────────

export interface WithGoogleAuthProps {
  googleAuth: GoogleAuthContextValue
}

// ─── HOC ───────────────────────────────────────────────────────────────────────

export function withGoogleAuth<P extends WithGoogleAuthProps>(
  Component: React.ComponentType<P>
): React.ComponentType<Omit<P, "googleAuth">> {
  const displayName =
    Component.displayName ?? Component.name ?? "Component"

  function WithGoogleAuthWrapper(props: Omit<P, "googleAuth">) {
    const auth = useGoogleAuth()
    return <Component {...(props as P)} googleAuth={auth} />
  }

  WithGoogleAuthWrapper.displayName = `withGoogleAuth(${displayName})`
  return WithGoogleAuthWrapper
}
