import React from "react"
import type { GretaAuthConfig, OAuthTokens, SignInWithOAuthOptions } from "../core"
import { useGoogleSignIn } from "./useGoogleSignIn"

// ─── Google G logo — 4-color SVG per brand guidelines ─────────────────────────

function GoogleIcon({ size = 18 }: { size?: number }) {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 48 48"
      width={size}
      height={size}
      aria-hidden="true"
    >
      <path
        fill="#EA4335"
        d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"
      />
      <path
        fill="#4285F4"
        d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"
      />
      <path
        fill="#FBBC05"
        d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"
      />
      <path
        fill="#34A853"
        d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.18 1.48-4.97 2.36-8.16 2.36-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"
      />
    </svg>
  )
}

// ─── Types ─────────────────────────────────────────────────────────────────────

export interface GoogleSignInButtonProps {
  /** Visual theme */
  theme?: "light" | "dark"
  /** Border shape */
  shape?: "rectangular" | "pill"
  /** Standard shows icon + text, icon shows only the G logo */
  variant?: "standard" | "icon"
  /** Button label (only shown in standard variant) */
  text?: string
  /** Called when sign-in completes successfully */
  onSuccess?: (tokens: OAuthTokens) => void
  /** Called when sign-in fails */
  onError?: (error: Error) => void
  /** Auth broker configuration forwarded to core.ts */
  config?: GretaAuthConfig
  /** Options forwarded to signInWithOAuth */
  options?: SignInWithOAuthOptions
  disabled?: boolean
  className?: string
  style?: React.CSSProperties
}

// ─── Styles ────────────────────────────────────────────────────────────────────

const BASE: React.CSSProperties = {
  display: "inline-flex",
  alignItems: "center",
  justifyContent: "center",
  border: "none",
  padding: 0,
  cursor: "pointer",
  fontFamily: "'Roboto', Arial, sans-serif",
  fontSize: "14px",
  fontWeight: 500,
  letterSpacing: "0.25px",
  lineHeight: 1,
  userSelect: "none",
  whiteSpace: "nowrap",
  outline: "none",
  transition: "background-color 0.218s, box-shadow 0.218s",
  height: "40px",
}

const LIGHT: React.CSSProperties = {
  backgroundColor: "#FFFFFF",
  color: "#3C4043",
  border: "1px solid #DADCE0",
  boxShadow:
    "0 1px 2px rgba(60,64,67,0.3), 0 1px 3px 1px rgba(60,64,67,0.15)",
}

const DARK: React.CSSProperties = {
  backgroundColor: "#131314",
  color: "#E3E3E3",
  border: "1px solid #8E918F",
}

const ICON_WRAPPER_DARK: React.CSSProperties = {
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  width: "20px",
  height: "20px",
  backgroundColor: "#FFFFFF",
  borderRadius: "2px",
}

// ─── Component ─────────────────────────────────────────────────────────────────

export function GoogleSignInButton({
  theme = "light",
  shape = "rectangular",
  variant = "standard",
  text = "Sign in with Google",
  onSuccess,
  onError,
  config,
  options,
  disabled,
  className,
  style,
}: GoogleSignInButtonProps) {
  const { signIn, loading } = useGoogleSignIn({
    config,
    onSuccess,
    onError,
  })

  const isIcon = variant === "icon"
  const isLight = theme === "light"
  const borderRadius = shape === "pill" ? "20px" : "4px"

  const buttonStyle: React.CSSProperties = {
    ...BASE,
    ...(isLight ? LIGHT : DARK),
    borderRadius,
    width: isIcon ? "40px" : undefined,
    padding: isIcon ? "0" : "0 12px 0 0",
    opacity: disabled || loading ? 0.6 : 1,
    cursor: disabled || loading ? "not-allowed" : "pointer",
    ...style,
  }

  // In the standard (non-icon) variant, the logo lives in its own 40×40 container
  const logoContainerStyle: React.CSSProperties = {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    width: "40px",
    height: "40px",
    flexShrink: 0,
  }

  const handleClick = () => {
    if (!disabled && !loading) signIn(options)
  }

  const label = loading ? "Signing in…" : text

  if (isIcon) {
    return (
      <button
        type="button"
        style={buttonStyle}
        className={className}
        disabled={disabled || loading}
        onClick={handleClick}
        aria-label={label}
      >
        {isLight ? (
          <GoogleIcon size={18} />
        ) : (
          <span style={ICON_WRAPPER_DARK}>
            <GoogleIcon size={18} />
          </span>
        )}
      </button>
    )
  }

  return (
    <button
      type="button"
      style={buttonStyle}
      className={className}
      disabled={disabled || loading}
      onClick={handleClick}
      aria-label={label}
    >
      {/* Icon column */}
      <span style={logoContainerStyle}>
        {isLight ? (
          <GoogleIcon size={18} />
        ) : (
          <span style={ICON_WRAPPER_DARK}>
            <GoogleIcon size={18} />
          </span>
        )}
      </span>

      {/* Label */}
      <span style={{ paddingRight: "12px" }}>{label}</span>
    </button>
  )
}
