export const EXPECTED_MESSAGE_TYPE = "authorization_response"
export const DEFAULT_OAUTH_BROKER_URL = "https://oauth.greta.sh/~oauth/initiate"
export const DEFAULT_SUPPORTED_OAUTH_ORIGINS = ["https://oauth.greta.sh"]
export const DEFAULT_MOBILE_DEEP_LINK_REDIRECT_URI = "greta://oauth-callback"
export const DEFAULT_DESKTOP_LOCALHOST_REDIRECT_URI = "http://127.0.0.1/iframe-oauth/callback"
export const POPUP_CHECK_INTERVAL_MS = 500
export const IFRAME_FALLBACK_TIMEOUT_MS = 120000

// ─── Types ─────────────────────────────────────────────────────────────────────

export type OAuthProvider = "google" | "apple"

export interface OAuthTokens {
  access_token: string
  refresh_token: string
}

export interface GretaAuthConfig {
  oauthBrokerUrl?: string
  supportedOAuthOrigins?: string[]
}

export interface SignInWithOAuthOptions {
  redirect_uri?: string
  extraParams?: Record<string, string>
}

export type SignInWithOAuthResult =
  | { tokens: OAuthTokens; error: null; redirected?: false }
  | { tokens?: undefined; error: Error; redirected?: false }
  | { tokens?: undefined; error: null; redirected: true }

// ─── Internal response shape from broker postMessage ───────────────────────────

interface OAuthResponseData {
  state?: string
  error?: string
  error_description?: string
  access_token?: string
  refresh_token?: string
}

// ─── Utilities (exact port of Lovable's implementation) ────────────────────────

export function generateState(): string {
  if (typeof crypto !== "undefined" && crypto.getRandomValues) {
    return [...crypto.getRandomValues(new Uint8Array(16))]
      .map((b) => b.toString(16).padStart(2, "0"))
      .join("")
  }
  return Math.random().toString(36).substring(2) + Date.now().toString(36)
}

export function isDevice(): boolean {
  const ua = navigator.userAgent
  if (/iPhone|iPad|iPod|Android/i.test(ua)) return true
  if (/Macintosh/i.test(ua) && navigator.maxTouchPoints > 1) return true
  return false
}

export function getPopupDimensions(inIframe: boolean): {
  width: number; height: number; left: number; top: number
} {
  const hasBrowserPosition =
    window.screenX !== 0 || window.screenY !== 0 || !inIframe
  const width = hasBrowserPosition
    ? window.outerWidth * 0.5
    : window.screen.width * 0.5
  const height = hasBrowserPosition
    ? window.outerHeight * 0.5
    : window.screen.height * 0.5
  const left = hasBrowserPosition
    ? window.screenX + (window.outerWidth - width) / 2
    : (window.screen.width - width) / 2
  const top = hasBrowserPosition
    ? window.screenY + (window.outerHeight - height) / 2
    : (window.screen.height - height) / 2
  return { width, height, left, top }
}

export function startWebMessageListener(supportedOrigins: string[]): {
  cleanup: () => void
  messagePromise: Promise<OAuthResponseData>
} {
  let resolvePromise!: (value: OAuthResponseData) => void
  const promise = new Promise<OAuthResponseData>((resolve) => {
    resolvePromise = resolve
  })

  const callback = (e: MessageEvent) => {
    const isValidOrigin = supportedOrigins.some((o) => e.origin === o)
    if (!isValidOrigin) return
    const data = e.data
    if (!data || typeof data !== "object") return
    if (data.type !== EXPECTED_MESSAGE_TYPE) return
    resolvePromise(data.response)
  }

  window.addEventListener("message", callback)

  return {
    cleanup: () => window.removeEventListener("message", callback),
    messagePromise: promise,
  }
}

export function processOAuthResponse(
  data: OAuthResponseData,
  expectedState: string
): SignInWithOAuthResult {
  if (data.state !== expectedState) {
    return { error: new Error("State is invalid") }
  }
  if (data.error) {
    return {
      error: new Error(data.error_description ?? "Sign in failed"),
    }
  }
  if (!data.access_token || !data.refresh_token) {
    return { error: new Error("No tokens received") }
  }
  return {
    tokens: {
      access_token: data.access_token,
      refresh_token: data.refresh_token,
    },
    error: null,
  }
}

// ─── Factory ───────────────────────────────────────────────────────────────────

export function createGretaAuth(config: GretaAuthConfig = {}) {
  const oauthBrokerUrl = config.oauthBrokerUrl ?? DEFAULT_OAUTH_BROKER_URL
  const supportedOAuthOrigins =
    config.supportedOAuthOrigins ?? DEFAULT_SUPPORTED_OAUTH_ORIGINS

  async function signInWithOAuth(
    provider: OAuthProvider,
    opts: SignInWithOAuthOptions = {}
  ): Promise<SignInWithOAuthResult> {
    let isInIframe = false
    try {
      isInIframe = window.self !== window.top
    } catch {
      isInIframe = true
    }

    const ua = navigator.userAgent
    const isMobileApp = /GretaApp\//.test(ua)
    const isDesktopApp = !isMobileApp && /greta/i.test(ua)


    const state = generateState()

    let redirectUri = opts.redirect_uri ?? window.location.origin
    if (isMobileApp && isInIframe) {
      redirectUri = DEFAULT_MOBILE_DEEP_LINK_REDIRECT_URI
    } else if (isDesktopApp && isInIframe) {
      redirectUri = DEFAULT_DESKTOP_LOCALHOST_REDIRECT_URI
    }

    const params = new URLSearchParams({
      ...opts.extraParams,
      provider,
      redirect_uri: redirectUri,
      state,
    })

    // Not in iframe → full page redirect
    if (!isInIframe) {
      window.location.href = `${oauthBrokerUrl}?${params.toString()}`
      return { error: null, redirected: true }
    }

    // In iframe → popup flow. Broker will redirect popup to /~oauth/relay on app's own origin.
    // That relay page does window.opener.postMessage back. We listen from window.location.origin.
    if (!isMobileApp && !isDesktopApp) {
      params.set("response_mode", "web_message")
    }

    const url = `${oauthBrokerUrl}?${params.toString()}`

    // Relay page is served at app's own origin (/~oauth/relay via CF Worker proxy).
    // window.opener survives because Google uses COOP: same-origin-allow-popups.
    // Fallback: also include supportedOAuthOrigins for non-Greta deployments.
    const effectiveOrigins = (!isMobileApp && !isDesktopApp)
      ? [window.location.origin, ...supportedOAuthOrigins]
      : isDesktopApp
        ? [...supportedOAuthOrigins, window.location.origin]
        : supportedOAuthOrigins

    const { messagePromise, cleanup } = startWebMessageListener(effectiveOrigins)

    let popup: Window | null
    if (isDevice()) {
      popup = window.open(url, "_blank")
    } else {
      const { width, height, left, top } = getPopupDimensions(isInIframe)
      popup = window.open(
        url,
        "oauth",
        `width=${width},height=${height},left=${left},top=${top}`
      )
    }


    // WebView fallback (no popup handle)
    if (!popup && (isMobileApp || isDesktopApp)) {
      let webViewTimeoutId: ReturnType<typeof setTimeout>
      const webViewTimeoutPromise = new Promise<never>((_, reject) => {
        webViewTimeoutId = setTimeout(
          () => reject(new Error("OAuth timed out waiting for response")),
          IFRAME_FALLBACK_TIMEOUT_MS
        )
      })
      try {
        const data = await Promise.race([messagePromise, webViewTimeoutPromise])
        return processOAuthResponse(data, state)
      } catch (error) {
        return { error: error instanceof Error ? error : new Error(String(error)) }
      } finally {
        clearTimeout(webViewTimeoutId!)
        cleanup()
      }
    }

    if (!popup) {
      cleanup()
      return { error: new Error("Popup was blocked") }
    }

    let popupCheckInterval: ReturnType<typeof setInterval>
    const popupClosedPromise = new Promise<never>((_, reject) => {
      popupCheckInterval = setInterval(() => {
        if (popup!.closed) {
          clearInterval(popupCheckInterval)
          reject(new Error("Sign in was cancelled"))
        }
      }, POPUP_CHECK_INTERVAL_MS)
    })

    try {
      const data = await Promise.race([messagePromise, popupClosedPromise])
      return processOAuthResponse(data, state)
    } catch (error) {
      return { error: error instanceof Error ? error : new Error(String(error)) }
    } finally {
      clearInterval(popupCheckInterval!)
      cleanup()
      popup?.close()
    }
  }

  return { signInWithOAuth }
}
