import { useCallback, useState } from "react"
import {
  type GretaAuthConfig,
  type OAuthTokens,
  type SignInWithOAuthOptions,
  createGretaAuth,
} from "../core"

// ─── Types ─────────────────────────────────────────────────────────────────────

export type SignInStatus = "idle" | "loading" | "success" | "error"

export interface UseGoogleSignInOptions {
  config?: GretaAuthConfig
  onSuccess?: (tokens: OAuthTokens) => void
  onError?: (error: Error) => void
}

export interface UseGoogleSignInResult {
  signIn: (options?: SignInWithOAuthOptions) => Promise<void>
  status: SignInStatus
  loading: boolean
  error: Error | null
  reset: () => void
}

// ─── Hook ──────────────────────────────────────────────────────────────────────

export function useGoogleSignIn(
  hookOptions?: UseGoogleSignInOptions
): UseGoogleSignInResult {
  const [status, setStatus] = useState<SignInStatus>("idle")
  const [error, setError] = useState<Error | null>(null)

  const signIn = useCallback(
    async (options?: SignInWithOAuthOptions) => {
      setStatus("loading")
      setError(null)

      try {
        const result = await createGretaAuth(hookOptions?.config).signInWithOAuth("google", options)

        if (result.redirected) {
          // Page is navigating away; leave status as loading
          return
        }

        if (result.error) {
          setStatus("error")
          setError(result.error)
          hookOptions?.onError?.(result.error)
          return
        }

        setStatus("success")
        hookOptions?.onSuccess?.(result.tokens)
      } catch (err) {
        const e = err instanceof Error ? err : new Error(String(err))
        setStatus("error")
        setError(e)
        hookOptions?.onError?.(e)
      }
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [hookOptions?.config, hookOptions?.onSuccess, hookOptions?.onError]
  )

  const reset = useCallback(() => {
    setStatus("idle")
    setError(null)
  }, [])

  return {
    signIn,
    status,
    loading: status === "loading",
    error,
    reset,
  }
}
