import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useState,
} from "react"
import {
  type GretaAuthConfig,
  type OAuthTokens,
  type SignInWithOAuthOptions,
  createGretaAuth,
} from "../core"

// ─── Types ─────────────────────────────────────────────────────────────────────

export interface GoogleUser {
  sub: string
  email: string
  email_verified: boolean
  name: string
  picture: string
  given_name: string
  family_name: string
}

export interface GoogleAuthContextValue {
  user: GoogleUser | null
  tokens: OAuthTokens | null
  loading: boolean
  error: Error | null
  initialized: boolean
  signIn: (options?: SignInWithOAuthOptions) => Promise<void>
  signOut: () => void
}

export interface GoogleAuthProviderProps {
  children: React.ReactNode
  config?: GretaAuthConfig
}

const SESSION_KEY = "google_auth_session"

interface StoredSession {
  tokens: OAuthTokens
  user: GoogleUser
}

// ─── Context ───────────────────────────────────────────────────────────────────

const GoogleAuthContext = createContext<GoogleAuthContextValue | null>(null)

async function fetchGoogleUser(accessToken: string): Promise<GoogleUser> {
  const res = await fetch("https://www.googleapis.com/oauth2/v3/userinfo", {
    headers: { Authorization: `Bearer ${accessToken}` },
  })
  if (!res.ok) throw new Error("Failed to fetch Google user info")
  return res.json() as Promise<GoogleUser>
}

// ─── Provider ──────────────────────────────────────────────────────────────────

export function GoogleAuthProvider({
  children,
  config,
}: GoogleAuthProviderProps) {
  const [user, setUser] = useState<GoogleUser | null>(null)
  const [tokens, setTokens] = useState<OAuthTokens | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<Error | null>(null)
  const [initialized, setInitialized] = useState(false)

  // Restore session on mount — handles both:
  // 1. Redirect flow: tokens arrive in URL hash after broker redirects back
  // 2. Existing session: restore from sessionStorage
  useEffect(() => {
    async function init() {
      // Check URL hash for tokens (redirect flow callback)
      const hash = new URLSearchParams(window.location.hash.slice(1))
      const accessToken = hash.get("access_token")
      const refreshToken = hash.get("refresh_token")

      if (accessToken) {
        // Clean the hash from the URL without triggering a navigation
        window.history.replaceState(null, "", window.location.pathname + window.location.search)

        try {
          setLoading(true)
          const googleUser = await fetchGoogleUser(accessToken)
          const t: OAuthTokens = { access_token: accessToken, refresh_token: refreshToken ?? "" }
          const session: StoredSession = { tokens: t, user: googleUser }
          sessionStorage.setItem(SESSION_KEY, JSON.stringify(session))
          setTokens(t)
          setUser(googleUser)
        } catch {
          // token in hash was invalid — ignore
        } finally {
          setLoading(false)
          setInitialized(true)
        }
        return
      }

      // No hash tokens — try restoring from sessionStorage
      try {
        const raw = sessionStorage.getItem(SESSION_KEY)
        if (raw) {
          const { tokens: t, user: u } = JSON.parse(raw) as StoredSession
          setTokens(t)
          setUser(u)
        }
      } catch {
        sessionStorage.removeItem(SESSION_KEY)
      } finally {
        setInitialized(true)
      }
    }

    init()
  }, [])

  const signIn = useCallback(
    async (options?: SignInWithOAuthOptions) => {
      setLoading(true)
      setError(null)

      try {
        const auth = createGretaAuth(config)
        const result = await auth.signInWithOAuth("google", options)

        if (result.redirected) return // navigating away — keep loading state

        if (result.error) {
          setError(result.error)
          return
        }

        console.log("✅ Google tokens received:")
        console.log("  access_token :", result.tokens.access_token)
        console.log("  refresh_token:", result.tokens.refresh_token)

        const googleUser = await fetchGoogleUser(result.tokens.access_token)

        const session: StoredSession = {
          tokens: result.tokens,
          user: googleUser,
        }
        sessionStorage.setItem(SESSION_KEY, JSON.stringify(session))

        setTokens(result.tokens)
        setUser(googleUser)
      } catch (err) {
        setError(err instanceof Error ? err : new Error(String(err)))
      } finally {
        setLoading(false)
      }
    },
    [config]
  )

  const signOut = useCallback(() => {
    sessionStorage.removeItem(SESSION_KEY)
    setUser(null)
    setTokens(null)
    setError(null)
  }, [])

  const value: GoogleAuthContextValue = {
    user,
    tokens,
    loading,
    error,
    initialized,
    signIn,
    signOut,
  }

  return (
    <GoogleAuthContext.Provider value={value}>
      {children}
    </GoogleAuthContext.Provider>
  )
}

// ─── Hook ──────────────────────────────────────────────────────────────────────

export function useGoogleAuth(): GoogleAuthContextValue {
  const ctx = useContext(GoogleAuthContext)
  if (!ctx) {
    throw new Error("useGoogleAuth must be used within a GoogleAuthProvider")
  }
  return ctx
}
