import { useEffect } from "react"

export type GretaUser = {
  sub: string
  name: string
  given_name: string
  family_name: string
  email: string
  email_verified: boolean
  picture: string
}

type CallbackHandlers = {
  onUser: (user: GretaUser, accessToken: string) => void
  onDone?: () => void
}

export function useGretaAuthCallback(
  onUserOrHandlers: ((user: GretaUser, accessToken: string) => void) | CallbackHandlers
) {
  useEffect(() => {
    // Redirect flow — read tokens from URL hash
    const handlers: CallbackHandlers =
      typeof onUserOrHandlers === "function"
        ? { onUser: onUserOrHandlers }
        : onUserOrHandlers

    const hash = new URLSearchParams(window.location.hash.slice(1))
    const accessToken = hash.get("access_token")

    if (!accessToken) {
      handlers.onDone?.()
      return
    }

    window.history.replaceState(null, "", window.location.pathname)

    fetch("https://www.googleapis.com/oauth2/v3/userinfo", {
      headers: { Authorization: `Bearer ${accessToken}` },
    })
      .then((r) => r.json())
      .then((user: GretaUser) => {
        handlers.onUser(user, accessToken)
        handlers.onDone?.()
      })
      .catch((e) => {
        console.error(e)
        handlers.onDone?.()
      })
  }, [])
}
